  1→//! Frontier tracking for concolic exploration.
  2→//!
  3→//! A frontier represents a branch reached but not fully explored during
  4→//! concolic execution. Each frontier tracks which parameters block progress
  5→//! and how many consecutive attempts have failed to make progress (stall count).
  6→//! The `FrontierSet` maintains a collection of frontiers per function,
  7→//! serving them in priority order: lower depth first, then lower stall count.
  8→
  9→use serde::{Deserialize, Serialize};
 10→
 11→/// Stall count threshold after which a frontier is considered deeply stalled.
 12→/// Consumers can use this to deprioritize or abandon frontiers that aren't
 13→/// making progress despite repeated attempts.
 14→pub const DEFAULT_MAX_STALL: u32 = 10;
 15→
 16→/// A single exploration frontier — a branch reached but not yet solved.
 17→///
 18→/// `blocking_params` lists the parameter indices (into the function's `ParamInfo`
 19→/// vec) that appear in the branch's symbolic constraint, identified via
 20→/// `sym_expr::extract_param_names`. `best_prefix` holds the input vector from
 21→/// the execution that reached this branch deepest.
 22→#[derive(Debug, Clone, Serialize, Deserialize)]
 23→pub struct Frontier {
 24→    /// Branch identifier, unique within the function scope.
 25→    pub branch_id: u32,
 26→    /// Nesting depth of this branch in the control-flow graph (0 = top-level).
 27→    pub depth: u32,
 28→    /// Indices of parameters that influence this branch's condition.
 29→    pub blocking_params: Vec<usize>,
 30→    /// Input vector from the best execution reaching this branch.
 31→    pub best_prefix: Vec<serde_json::Value>,
 32→    /// Consecutive failed attempts to solve past this branch.
 33→    pub stall_count: u32,
 34→}
 35→
 36→/// Priority-ordered collection of frontiers for a single function.
 37→///
 38→/// Frontiers are served lowest-depth first (shallowest branches are explored
 39→/// before deeper ones), with stall count as a tiebreaker (less-stalled
 40→/// frontiers are preferred). The set is typically small (< 100 entries),
 41→/// so linear scans are acceptable.
 42→#[derive(Debug, Clone, Default)]
 43→pub struct FrontierSet {
 44→    frontiers: Vec<Frontier>,
 45→}
 46→
 47→impl FrontierSet {
 48→    pub fn new() -> Self {
 49→        Self::default()
 50→    }
 51→
 52→    /// Insert a frontier. If a frontier with the same `branch_id` already
 53→    /// exists, it is replaced.
 54→    pub fn insert(&mut self, frontier: Frontier) {
 55→        self.remove(frontier.branch_id);
 56→        self.frontiers.push(frontier);
 57→    }
 58→
 59→    /// Remove and return the highest-priority frontier (lowest depth, then
 60→    /// lowest stall count).
 61→    pub fn pop_highest_priority(&mut self) -> Option<Frontier> {
 62→        if self.frontiers.is_empty() {
 63→            return None;
 64→        }
 65→        let idx = self.best_index();
 66→        Some(self.frontiers.swap_remove(idx))
 67→    }
 68→
 69→    /// View the highest-priority frontier without removing it.
 70→    pub fn peek(&self) -> Option<&Frontier> {
 71→        if self.frontiers.is_empty() {
 72→            return None;
 73→        }
 74→        let idx = self.best_index();
 75→        Some(&self.frontiers[idx])
 76→    }
 77→
 78→    /// Increment the stall count for the frontier with the given `branch_id`.
 79→    /// Returns `true` if the frontier was found and updated.
 80→    pub fn increment_stall(&mut self, branch_id: u32) -> bool {
 81→        if let Some(f) = self.frontiers.iter_mut().find(|f| f.branch_id == branch_id) {
 82→            f.stall_count = f.stall_count.saturating_add(1);
 83→            true
 84→        } else {
 85→            false
 86→        }
 87→    }
 88→
 89→    /// Remove the frontier with the given `branch_id` (e.g., after solving it).
 90→    /// Returns the removed frontier, if any.
 91→    pub fn remove(&mut self, branch_id: u32) -> Option<Frontier> {
 92→        if let Some(pos) = self.frontiers.iter().position(|f| f.branch_id == branch_id) {
 93→            Some(self.frontiers.swap_remove(pos))
 94→        } else {
 95→            None
 96→        }
 97→    }
 98→
 99→    pub fn len(&self) -> usize {
100→        self.frontiers.len()
101→    }
102→
103→    pub fn is_empty(&self) -> bool {
104→        self.frontiers.is_empty()
105→    }
106→
107→    /// Iterate over all frontiers in arbitrary order.
108→    pub fn iter(&self) -> impl Iterator<Item = &Frontier> {
109→        self.frontiers.iter()
110→    }
111→
112→    /// Index of the highest-priority frontier.
113→    /// Caller must ensure `self.frontiers` is non-empty.
114→    fn best_index(&self) -> usize {
115→        self.frontiers
116→            .iter()
117→            .enumerate()
118→            .min_by(|(_, a), (_, b)| frontier_priority(a, b))
119→            .map(|(i, _)| i)
120→            .expect("best_index called on non-empty FrontierSet")
121→    }
122→}
123→
124→/// Compare two frontiers for priority ordering.
125→/// Lower depth wins; ties broken by lower stall count.
126→fn frontier_priority(a: &Frontier, b: &Frontier) -> std::cmp::Ordering {
127→    a.depth.cmp(&b.depth).then(a.stall_count.cmp(&b.stall_count))
128→}
129→
130→#[cfg(test)]
131→mod tests {
132→    use super::*;
133→
134→    fn make_frontier(branch_id: u32, depth: u32, stall_count: u32) -> Frontier {
135→        Frontier {
136→            branch_id,
137→            depth,
138→            blocking_params: vec![],
139→            best_prefix: vec![],
140→            stall_count,
141→        }
142→    }
143→
144→    #[test]
145→    fn empty_set_returns_none() {
146→        let mut set = FrontierSet::new();
147→        assert!(set.is_empty());
148→        assert_eq!(set.len(), 0);
149→        assert!(set.peek().is_none());
150→        assert!(set.pop_highest_priority().is_none());
151→    }
152→
153→    #[test]
154→    fn single_insert_and_pop() {
155→        let mut set = FrontierSet::new();
156→        set.insert(make_frontier(1, 3, 0));
157→        assert_eq!(set.len(), 1);
158→
159→        let f = set.pop_highest_priority().unwrap();
160→        assert_eq!(f.branch_id, 1);
161→        assert!(set.is_empty());
162→    }
163→
164→    #[test]
165→    fn priority_lower_depth_first() {
166→        let mut set = FrontierSet::new();
167→        set.insert(make_frontier(1, 5, 0));
168→        set.insert(make_frontier(2, 2, 0));
169→        set.insert(make_frontier(3, 8, 0));
170→
171→        let f = set.pop_highest_priority().unwrap();
172→        assert_eq!(f.branch_id, 2, "shallowest branch should be popped first");
173→
174→        let f = set.pop_highest_priority().unwrap();
175→        assert_eq!(f.branch_id, 1);
176→
177→        let f = set.pop_highest_priority().unwrap();
178→        assert_eq!(f.branch_id, 3);
179→    }
180→
181→    #[test]
182→    fn priority_stall_count_breaks_ties() {
183→        let mut set = FrontierSet::new();
184→        set.insert(make_frontier(1, 3, 5));
185→        set.insert(make_frontier(2, 3, 1));
186→        set.insert(make_frontier(3, 3, 3));
187→
188→        let f = set.pop_highest_priority().unwrap();
189→        assert_eq!(f.branch_id, 2, "lowest stall count wins at equal depth");
190→
191→        let f = set.pop_highest_priority().unwrap();
192→        assert_eq!(f.branch_id, 3);
193→    }
194→
195→    #[test]
196→    fn duplicate_branch_id_replaces() {
197→        let mut set = FrontierSet::new();
198→        set.insert(make_frontier(1, 5, 0));
199→        set.insert(make_frontier(1, 2, 3));
200→
201→        assert_eq!(set.len(), 1);
202→        let f = set.peek().unwrap();
203→        assert_eq!(f.depth, 2, "second insert should replace the first");
204→    }
205→
206→    #[test]
207→    fn increment_stall_updates_count() {
208→        let mut set = FrontierSet::new();
209→        set.insert(make_frontier(1, 3, 0));
210→
211→        assert!(set.increment_stall(1));
212→        assert_eq!(set.peek().unwrap().stall_count, 1);
213→
214→        assert!(set.increment_stall(1));
215→        assert_eq!(set.peek().unwrap().stall_count, 2);
216→    }
217→
218→    #[test]
219→    fn increment_stall_missing_returns_false() {
220→        let mut set = FrontierSet::new();
221→        assert!(!set.increment_stall(99));
222→    }
223→
224→    #[test]
225→    fn remove_by_branch_id() {
226→        let mut set = FrontierSet::new();
227→        set.insert(make_frontier(1, 3, 0));
228→        set.insert(make_frontier(2, 5, 0));
229→
230→        let removed = set.remove(1);
231→        assert!(removed.is_some());
232→        assert_eq!(removed.unwrap().branch_id, 1);
233→        assert_eq!(set.len(), 1);
234→
235→        assert!(set.remove(1).is_none());
236→    }
237→
238→    #[test]
239→    fn iter_yields_all_frontiers() {
240→        let mut set = FrontierSet::new();
241→        set.insert(make_frontier(1, 3, 0));
242→        set.insert(make_frontier(2, 5, 0));
243→        set.insert(make_frontier(3, 1, 0));
244→
245→        let ids: Vec<u32> = set.iter().map(|f| f.branch_id).collect();
246→        assert_eq!(ids.len(), 3);
247→        assert!(ids.contains(&1));
248→        assert!(ids.contains(&2));
249→        assert!(ids.contains(&3));
250→    }
251→
252→    #[test]
253→    fn peek_matches_pop() {
254→        let mut set = FrontierSet::new();
255→        set.insert(make_frontier(1, 5, 0));
256→        set.insert(make_frontier(2, 2, 0));
257→
258→        let peeked_id = set.peek().unwrap().branch_id;
259→        let popped_id = set.pop_highest_priority().unwrap().branch_id;
260→        assert_eq!(peeked_id, popped_id);
261→    }
262→
263→    #[test]
264→    fn blocking_params_and_best_prefix_preserved() {
265→        let mut set = FrontierSet::new();
266→        set.insert(Frontier {
267→            branch_id: 1,
268→            depth: 0,
269→            blocking_params: vec![0, 2],
270→            best_prefix: vec![serde_json::json!(42), serde_json::json!("hello")],
271→            stall_count: 0,
272→        });
273→
274→        let f = set.peek().unwrap();
275→        assert_eq!(f.blocking_params, vec![0, 2]);
276→        assert_eq!(f.best_prefix.len(), 2);
277→    }
278→
279→    #[test]
280→    fn stall_count_saturates() {
281→        let mut set = FrontierSet::new();
282→        set.insert(make_frontier(1, 0, u32::MAX));
283→        assert!(set.increment_stall(1));
284→        assert_eq!(set.peek().unwrap().stall_count, u32::MAX);
285→    }
286→}
