186→    #[test]
187→    fn sym_constraint_expr_round_trips() {
188→        round_trip(&SymConstraint::Expr {
189→            expr: SymExpr::BinOp {
190→                op: BinOpKind::Gt,
191→                left: Box::new(SymExpr::Param {
192→                    name: "x".into(),
193→                    path: vec![],
194→                }),
195→                right: Box::new(SymExpr::Const(ConstValue::Int(10))),
196→            },
197→        });
198→    }
